+/// Process-wide placeholder `VdbeProgram` shared across all prepared
+/// statements that don't compile to real bytecode (the SELECT-dispatch
+/// and deferred paths hand this to the `PreparedStatement::program`
+/// field as a filler).
+///
+/// `ProgramBuilder::new().finish()` is a pure constant — an empty `ops`
+/// SmallVec, zero labels, zero bind parameters, zero registers. Before
+/// caching it, `build_placeholder_program()` was invoked from five
+/// distinct `prepare()` branches and showed up as 2.66% self-time of
+/// `__memmove_avx_unaligned_erms` on the 2026-04-23 MT 8t DWARF capture
+/// (`fsqlite-memmove-dwarf-213322`), with the memcpy coming from
+/// `Arc::new(VdbeProgram { .. })` moving the struct into a fresh arc
+/// allocation every call.
+///
+/// The cached arc is cloned on each call — a single atomic refcount inc
+/// instead of a full allocation + struct memcpy.
+static PLACEHOLDER_PROGRAM: OnceLock<Arc<VdbeProgram>> = OnceLock::new();
+
 fn build_placeholder_program() -> Result<Arc<VdbeProgram>> {
-    Ok(Arc::new(ProgramBuilder::new().finish().map_err(|e| {
+    if let Some(cached) = PLACEHOLDER_PROGRAM.get() {
+        return Ok(Arc::clone(cached));
+    }
+    let program = ProgramBuilder::new().finish().map_err(|e| {
         FrankenError::Internal(format!("failed to build placeholder program: {e}"))
-    })?))
+    })?;
+    let arc = Arc::new(program);
+    // If another thread raced ahead and populated the OnceLock, prefer its
+    // arc and drop ours; either way the returned clone is authoritative.
+    let canonical = PLACEHOLDER_PROGRAM.get_or_init(|| arc);
+    Ok(Arc::clone(canonical))
 }

